[CmdletBinding(SupportsShouldProcess)]
param(
    [Parameter(Mandatory)]
    [ValidateNotNullOrEmpty()]
    [string]$ProjectRoot,

    [switch]$Clean
)

Set-StrictMode -Version Latest
$ErrorActionPreference = 'Stop'

try {
    Push-Location -LiteralPath $ProjectRoot

    if ($Clean -and $PSCmdlet.ShouldProcess('build', 'Remove build directory')) {
        Remove-Item -Recurse -Force build -ErrorAction SilentlyContinue
    }
}
catch {
    Write-Error $_
    exit 1
}
finally {
    Pop-Location
}

function Invoke-BuildStep {
    [CmdletBinding()]
    param(
        [Parameter(Mandatory)]
        [string]$Name,

        [Parameter(Mandatory)]
        [scriptblock]$Action
    )

    Write-Host "=== $Name ==="
    & $Action

    if ($LASTEXITCODE -ne 0) {
        throw "Step failed: $Name ($LASTEXITCODE)"
    }
}

function Remove-Deployment {
    [CmdletBinding(SupportsShouldProcess, ConfirmImpact = 'High')]
    param(
        [Parameter(Mandatory)]
        [string]$Path
    )

    if ($PSCmdlet.ShouldProcess($Path, 'Remove deployment')) {
        Remove-Item -Recurse -Force -LiteralPath $Path
    }
}

Remove-Deployment -Path $DeployDir -WhatIf

try {
    Invoke-Operation
}
catch {
    Write-Error $_
}
finally {
    Close-Resources
}

Import-Module ThreadJob
$job = Start-ThreadJob -ScriptBlock { Invoke-Work }
Wait-Job $job | Receive-Job

$session = New-PSSession -ComputerName $HostName
try {
    Invoke-Command -Session $session -ScriptBlock { hostname }
}
finally {
    Remove-PSSession $session
}

cmake -S . -B build -DCMAKE_BUILD_TYPE=Release
if ($LASTEXITCODE -ne 0) { exit $LASTEXITCODE }
cmake --build build --parallel
if ($LASTEXITCODE -ne 0) { exit $LASTEXITCODE }
ctest --test-dir build --output-on-failure

setlocal EnableDelayedExpansion
for %%F in (*.txt) do (
    set "CURRENT=%%~fF"
    echo !CURRENT!
)

for %%F in ("%SOURCE_DIR%\*.dll") do (
    echo Copying %%~nxF
    copy /y "%%~fF" "%TARGET_DIR%\"
)

for /f "usebackq tokens=*" %%L in (`git rev-parse --short HEAD`) do (
    set "GIT_SHA=%%L"
)

:wait
tasklist /fi "imagename eq myTool.exe" | findstr /i "myTool.exe" >nul
if not errorlevel 1 (
    timeout /t 1 /nobreak >nul
    goto :wait
)

#!/usr/bin/env bash
set -Eeuo pipefail
IFS=$'\n\t'

SCRIPT_DIR="$(cd -- "$(dirname -- "${BASH_SOURCE[0]}")" && pwd)"

cleanup() {
  : # release temporary resources
}

on_error() {
  local exit_code=$?
  printf 'ERROR line=%s exit=%s\n' "${BASH_LINENO[0]}" "$exit_code" >&2
  exit "$exit_code"
}

trap cleanup EXIT
trap on_error ERR

#!/bin/sh
set -eu

SCRIPT_DIR=$(CDPATH= cd -- "$(dirname -- "$0")" && pwd)

cleanup() {
  :
}

trap cleanup EXIT HUP INT TERM

while getopts ":c:o:v" option; do
  case "$option" in
    c) config_file="$OPTARG" ;;
    o) output_dir="$OPTARG" ;;
    v) verbose=1 ;;
    *) exit 2 ;;
  esac
done
shift $((OPTIND - 1))

while (($#)); do
  case "$1" in
    --config) config_file="$2"; shift 2 ;;
    --dry-run) dry_run=1; shift ;;
    --) shift; break ;;
    *) printf "Unknown option: %s\n" "$1" >&2; exit 2 ;;
  esac
done

case "$mode" in
  debug) echo "debug" ;;
  release) echo "release" ;;
  *) printf "Unsupported mode\n" >&2; exit 2 ;;
esac

Host {{alias}}
  HostName {{hostname}}
  User {{user}}
  Port {{port}}
  IdentityFile {{identity}}
  IdentitiesOnly yes
  ServerAliveInterval 30
